<?php
namespace Tests\Feature\Admin\Content;
use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Hunts\Rewards\HuntRewardStatus;use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Domain\Loot\LootGenerator;use App\Models\Character;use App\Models\HuntRewardItem;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use App\Models\User;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class AdminContentTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();config(['game_admin.emails'=>['admin@example.test']]);$this->admin=User::factory()->create(['email'=>'admin@example.test']);}private function item($overrides=[]){return array_merge(['code'=>'admin_sword','name'=>'Admin Sword','description'=>'Internal content','item_type'=>'equipment','equipment_type'=>'weapon','hand_requirement'=>'one_hand','equipment_family'=>'sword','rarity'=>'common','is_stackable'=>0,'max_stack'=>1,'status'=>'active','max_health_bonus'=>0,'attack_bonus'=>5,'defense_bonus'=>0,'accuracy_bonus'=>0,'evasion_bonus'=>0,'critical_chance_bonus'=>0,'attack_speed_bonus'=>0],$overrides);}private function monster($overrides=[]){return array_merge(['code'=>'admin_monster','name'=>'Admin Monster','description'=>'Internal content','level'=>2,'max_health'=>25,'attack'=>6,'defense'=>3,'accuracy_rate'=>75,'evasion_rate'=>4,'critical_chance'=>2,'experience_reward'=>15,'gold_min'=>1,'gold_max'=>3,'status'=>'active'],$overrides);}public function test_access_is_authorized_by_isolated_email_middleware(){$this->get(route('admin.content.items.index'))->assertRedirect('/login');$this->actingAs(User::factory()->create())->get(route('admin.content.items.index'))->assertForbidden();$this->actingAs($this->admin)->get(route('admin.content.items.index'))->assertOk();}public function test_item_crud_reuses_equipment_rules_and_delete_only_deactivates(){$this->actingAs($this->admin)->post(route('admin.content.items.store'),$this->item())->assertRedirect();$item=Item::where('code','admin_sword')->firstOrFail();$this->assertSame('weapon',app(EquippableItemValidator::class)->equipmentType($item));$this->post(route('admin.content.items.store'),$this->item(['code'=>'bad_material','item_type'=>'material','equipment_type'=>null,'is_stackable'=>1,'max_stack'=>10]))->assertSessionHasErrors('content');$this->assertDatabaseMissing('items',['code'=>'bad_material']);$this->delete(route('admin.content.items.destroy',$item))->assertRedirect();$this->assertSame('inactive',$item->fresh()->status);$this->assertDatabaseHas('items',['id'=>$item->id]);}public function test_monster_crud_is_usable_by_loot_generator(){$this->actingAs($this->admin)->post(route('admin.content.monsters.store'),$this->monster())->assertRedirect();$monster=Monster::where('code','admin_monster')->firstOrFail();$this->assertSame($monster->id,app(LootGenerator::class)->generateFor($monster)->monsterId());$this->put(route('admin.content.monsters.update',$monster),$this->monster(['name'=>'Balanced Monster']))->assertRedirect();$this->assertSame('Balanced Monster',$monster->fresh()->name);$this->delete(route('admin.content.monsters.destroy',$monster));$this->assertSame('inactive',$monster->fresh()->status);}public function test_zone_crud_and_monster_assignment_preserve_hierarchy(){$this->seed(WorldCatalogSeeder::class);$region=\App\Models\Region::firstOrFail();$monster=Monster::firstOrFail();$payload=['region_id'=>$region->id,'code'=>'admin_zone','name'=>'Admin Zone','description'=>null,'zone_type'=>'field','recommended_level_min'=>1,'recommended_level_max'=>5,'is_safe'=>0,'allows_hunting'=>1,'status'=>'active','sort_order'=>99];$this->actingAs($this->admin)->post(route('admin.content.zones.store'),$payload)->assertRedirect();$zone=Zone::where('code','admin_zone')->firstOrFail();$this->post(route('admin.content.zones.monsters.store',$zone),['monster_id'=>$monster->id,'weight'=>70,'minimum_character_level'=>1,'maximum_character_level'=>5,'status'=>'active'])->assertRedirect();$this->assertDatabaseHas('zone_monsters',['zone_id'=>$zone->id,'monster_id'=>$monster->id,'weight'=>70]);$this->get(route('admin.content.zones.show',$zone))->assertOk()->assertSee($region->world->name)->assertSee($region->name)->assertSee($zone->name);$this->delete(route('admin.content.zones.destroy',$zone));$this->assertSame('inactive',$zone->fresh()->status);}public function test_admin_loot_validation_and_reward_integration(){$this->seed(WorldCatalogSeeder::class);$this->actingAs($this->admin)->post(route('admin.content.items.store'),$this->item(['code'=>'admin_drop','item_type'=>'material','equipment_type'=>null,'is_stackable'=>1,'max_stack'=>20,'attack_bonus'=>0]))->assertRedirect();$this->post(route('admin.content.monsters.store'),$this->monster(['code'=>'admin_reward_monster','attack'=>0,'max_health'=>1]))->assertRedirect();$item=Item::where('code','admin_drop')->firstOrFail();$monster=Monster::where('code','admin_reward_monster')->firstOrFail();$this->post(route('admin.content.monsters.loot.store',$monster),['item_id'=>$item->id,'drop_chance_basis_points'=>10000,'minimum_quantity'=>1,'maximum_quantity'=>1,'status'=>'active','sort_order'=>1])->assertRedirect();$this->assertCount(1,app(LootGenerator::class)->generateFor($monster)->drops());$this->post(route('admin.content.monsters.loot.store',$monster),['item_id'=>$item->id,'drop_chance_basis_points'=>10001,'minimum_quantity'=>1,'maximum_quantity'=>1,'status'=>'active','sort_order'=>1])->assertSessionHasErrors();$zone=Zone::where('code','grey_oak_forest')->firstOrFail();DB::table('zone_monsters')->where('zone_id',$zone->id)->update(['status'=>'inactive']);$this->post(route('admin.content.zones.monsters.store',$zone),['monster_id'=>$monster->id,'weight'=>100,'minimum_character_level'=>1,'maximum_character_level'=>null,'status'=>'active']);$character=Character::factory()->for(User::factory())->create(['base_attack'=>500]);CarbonImmutable::setTestNow('2026-07-16 12:00:00');$sessions=app(HuntingSessionService::class);$session=\App\Models\HuntingSession::findOrFail($sessions->start($character,$zone)->id());$sessions->tick($character,$session);$this->assertDatabaseHas('hunt_reward_items',['item_id'=>$item->id]);CarbonImmutable::setTestNow();}}
